import axios from 'axios';

const api = axios.create({
  baseURL: 'http://localhost:5000', // your backend URL
});

export const registerUser = async (userData) => {
  return await api.post('/auth/register', userData);
};

export const loginUser = async (loginData) => {
  return await api.post('/auth/login', loginData);
};

export const createComplaint = async (complaintData, token) => {
  return await api.post('/complaints', complaintData, {
    headers: { Authorization: `Bearer ${token}` },
  });
};

export const getComplaints = async () => {
  return await api.get('/complaints');
};

export const getComplaintById = async (id) => {
  return await api.get(`/complaints/${id}`);
};

export const updateComplaint = async (id, complaintData, token) => {
  return await api.put(`/complaints/${id}`, complaintData, {
    headers: { Authorization: `Bearer ${token}` },
  });
};

export const deleteComplaint = async (id, token) => {
  return await api.delete(`/complaints/${id}`, {
    headers: { Authorization: `Bearer ${token}` },
  });
};
